// Archivo: avanzado.js (NIVEL AVANZADO: Preguntas 1 a 100)
export const preguntasNivel3 = [
  { id: 1, curso: "Red Hat System Administration I", pregunta: "¿Cómo diagnosticarías un problema de inicio cuando un servicio falla por dependencia de otro servicio?", opciones: ["Reiniciando el servidor inmediatamente.", "Usando 'systemctl list-dependencies <servicio>' y revisando 'journalctl -xe' para ver qué dependencia falló.", "Eliminando el archivo de servicio.", "Desactivando todas las dependencias en el archivo .service.", "No se puede diagnosticar, hay que reinstalar."], respuestaCorrecta: 1, explicacion: "systemctl list-dependencies muestra el árbol de dependencias, y journalctl permite ver los logs de error específicos de la unidad que falló al iniciar." },
  { id: 2, curso: "Red Hat System Administration I", pregunta: "¿Cómo interpretarías un journalctl con errores de SELinux y qué pasos seguirías para aislar la causa?", opciones: ["Ignorar los errores, SELinux suele dar falsos positivos.", "Usar 'ausearch -m avc -ts recent' o 'sealert -a /var/log/audit/audit.log' para obtener una explicación legible y la solución sugerida.", "Desactivar SELinux permanentemente con 'setenforce 0'.", "Borrar los logs de auditoría.", "Reinstalar el paquete que genera el error."], respuestaCorrecta: 1, explicacion: "Las herramientas ausearch y sealert analizan los logs de denegación de SELinux (AVC) y proporcionan comandos exactos (como restorecon o semanage) para resolver el problema de forma segura." },
  { id: 3, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencia práctica hay entre cambiar un contexto SELinux temporalmente y corregirlo de forma persistente?", opciones: ["No hay diferencia, ambos son permanentes.", "Temporal usa 'chcon' (se pierde al restaurar contextos), persistente usa 'semanage fcontext' + 'restorecon' (sobrevive a reinicios y restauraciones).", "Temporal es más seguro que persistente.", "Persistente solo funciona en modo permissive.", "chcon modifica el kernel, semanage modifica archivos."], respuestaCorrecta: 1, explicacion: "chcon cambia el contexto en el momento, pero un 'restorecon' lo revertirá. semanage fcontext añade una regla a la política local que restorecon aplicará siempre." },
  { id: 4, curso: "Red Hat System Administration I", pregunta: "¿Cómo verificarías y restaurarías los contextos correctos de SELinux en un directorio completo?", opciones: ["ls -Z para verificar, restorecon -Rv /ruta para restaurar.", "getenforce para verificar, setenforce 1 para restaurar.", "cat /etc/selinux/config para verificar, chcon para restaurar.", "sestatus para verificar, rm -rf para restaurar.", "No se puede restaurar, hay que formatear."], respuestaCorrecta: 0, explicacion: "ls -Z muestra los contextos de seguridad actuales. restorecon -Rv (recursivo y verbose) restablece los contextos a los valores por defecto definidos en la política de SELinux." },
  { id: 5, curso: "Red Hat System Administration I", pregunta: "¿Qué son las ACLs en Linux y en qué caso son mejores que los permisos tradicionales?", opciones: ["Son listas de control de acceso que permiten dar permisos granulares a usuarios o grupos específicos, superando la limitación de solo Propietario/Grupo/Otros.", "Son firewalls de aplicaciones.", "Son listas de archivos prohibidos.", "Son permisos que solo funcionan en Windows.", "Son iguales a los permisos tradicionales, solo cambia el nombre."], respuestaCorrecta: 0, explicacion: "Los permisos tradicionales (rwx para u, g, o) son limitados. Las ACLs (Access Control Lists) permiten asignar permisos específicos a múltiples usuarios o grupos individuales sobre un mismo archivo." },
  { id: 6, curso: "Red Hat System Administration I", pregunta: "¿Cómo revisarías, agregarías y eliminarías ACLs de un archivo o directorio?", opciones: ["getfacl para revisar, setfacl -m para agregar, setfacl -x para eliminar.", "ls -l para revisar, chmod para agregar, rm para eliminar.", "cat acl para revisar, addacl para agregar, delacl para eliminar.", "getperm para revisar, setperm para agregar, rmperm para eliminar.", "No se pueden eliminar, solo agregar."], respuestaCorrecta: 0, explicacion: "getfacl muestra las ACLs actuales. setfacl -m (modify) agrega o modifica reglas, y setfacl -x (remove) elimina reglas específicas de la ACL." },
  { id: 7, curso: "Red Hat System Administration I", pregunta: "¿Qué problemas pueden aparecer si un archivo tiene permisos correctos pero sigue sin abrirse?", opciones: ["SELinux lo está bloqueando, tiene atributos inmutables (chattr +i), o una ACL denegatoria está activa.", "El archivo está corrupto siempre.", "El disco está lleno de inodos.", "El sistema operativo está desactualizado.", "No hay problemas, es un error del usuario."], respuestaCorrecta: 0, explicacion: "Además de los permisos POSIX básicos, SELinux, las ACLs y los atributos extendidos del sistema de archivos (como 'i' de inmutable o 'a' de solo-append) pueden denegar el acceso." },
  { id: 8, curso: "Red Hat System Administration I", pregunta: "¿Cómo usarías sudo para limitar comandos específicos a un usuario o grupo?", opciones: ["Editando /etc/sudoers con visudo y especificando la ruta absoluta del comando permitido, ej: 'usuario ALL=(root) /usr/bin/systemctl restart nginx'.", "Dándole la contraseña de root al usuario.", "Agregando al usuario al grupo root.", "Usando chmod 777 en el comando.", "No se puede limitar, sudo es todo o nada."], respuestaCorrecta: 0, explicacion: "visudo permite definir reglas granulares. Especifcar la ruta absoluta del ejecutable evita que el usuario ejecute otros comandos con el mismo nombre desde otras ubicaciones." },
  { id: 9, curso: "Red Hat System Administration I", pregunta: "¿Qué riesgos tiene una regla mal escrita en /etc/sudoers?", opciones: ["Puede otorgar privilegios de root totales de forma no intencionada (ej. permitir editar cualquier archivo o ejecutar cualquier comando).", "Ninguno, el sistema lo corrige automáticamente.", "Solo ralentiza el sistema.", "Desactiva la red.", "Borra el archivo sudoers."], respuestaCorrecta: 0, explicacion: "Una regla como 'usuario ALL=(ALL) NOPASSWD: ALL' o permitir editar archivos con editores que permiten ejecutar shell (como vi) otorga escalada de privilegios completa." },
  { id: 10, curso: "Red Hat System Administration I", pregunta: "¿Cómo auditarías qué usuarios tienen privilegios de administración en el sistema?", opciones: ["Revisando el grupo 'wheel' o 'sudo' con 'getent group', y analizando el archivo /etc/sudoers y /etc/sudoers.d/.", "Preguntando a los usuarios.", "Revisando el historial de bash de root.", "Usando el comando 'whoami'.", "No se puede auditar."], respuestaCorrecta: 0, explicacion: "La administración en Linux se gestiona principalmente a través de la membresía en grupos privilegiados (wheel/sudo) y las reglas explícitas definidas en los archivos sudoers." },
  { id: 11, curso: "Red Hat System Administration I", pregunta: "¿Cómo resolverías un sistema que arranca en modo de emergencia por un error en /etc/fstab?", opciones: ["Ingresar la contraseña de root, comentar o corregir la línea errónea en /etc/fstab con un editor, y reiniciar.", "Reinstalar el sistema operativo.", "Borrar el archivo /etc/fstab.", "Desactivar SELinux.", "No tiene solución, se requieren discos nuevos."], respuestaCorrecta: 0, explicacion: "El modo de emergencia proporciona un shell de root con el sistema de archivos raíz montado (a veces en solo lectura, requiriendo 'mount -o remount,rw /'). Corregir fstab permite un arranque normal." },
  { id: 12, curso: "Red Hat System Administration I", pregunta: "¿Cómo distinguirías entre un problema de montaje manual y uno de montaje automático al iniciar?", opciones: ["Si 'mount /dev/sdX /mnt' funciona pero falla al reiniciar, el problema está en la configuración de /etc/fstab o en la unidad systemd de montaje.", "Si funciona manual, nunca es un problema de fstab.", "El montaje automático no existe en Linux.", "El montaje manual siempre falla si fstab está mal.", "No hay forma de distinguirlo."], respuestaCorrecta: 0, explicacion: "Un montaje manual exitoso descarta problemas de hardware o sistema de archivos. Si falla en el arranque, la causa es la configuración persistente (fstab, opciones incorrectas, 'nofail' faltante, o dispositivo no disponible a tiempo)." },
  { id: 13, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencias hay entre LVM y particiones tradicionales en administración de discos?", opciones: ["LVM permite redimensionar, combinar y mover volúmenes lógicos entre discos físicos de forma flexible sin reparticionar.", "LVM es más lento en todos los aspectos.", "Las particiones tradicionales permiten redimensionamiento en caliente.", "LVM no soporta sistemas de archivos modernos.", "No hay diferencia, LVM es solo un nombre comercial."], respuestaCorrecta: 0, explicacion: "LVM (Logical Volume Manager) abstrae el almacenamiento físico, permitiendo agrupar discos (VG) y crear volúmenes (LV) que pueden crecer o encogerse dinámicamente, a diferencia de las particiones fijas." },
  { id: 14, curso: "Red Hat System Administration I", pregunta: "¿Cómo ampliarías un volumen lógico sin perder datos?", opciones: ["Usar 'lvextend' para ampliar el volumen lógico y luego 'resize2fs' (ext4) o 'xfs_growfs' (xfs) para expandir el sistema de archivos.", "Borrar el volumen y crear uno nuevo.", "Usar 'fdisk' para crear una partición nueva y copiar datos.", "LVM no permite ampliación sin pérdida de datos.", "Usar 'lvreduce'."], respuestaCorrecta: 0, explicacion: "El proceso seguro es primero expandir el contenedor lógico (lvextend) y luego instruir al sistema de archivos para que use el nuevo espacio disponible (resize2fs/xfs_growfs)." },
  { id: 15, curso: "Red Hat System Administration I", pregunta: "¿Qué pasos seguirías para reducir el tamaño de un sistema de archivos con seguridad?", opciones: ["Desmontar el sistema de archivos, ejecutar fsck, reducir el sistema de archivos (resize2fs) y luego reducir el volumen lógico (lvreduce).", "Ejecutar lvreduce directamente sin desmontar.", "Borrar archivos y ejecutar lvreduce.", "No se puede reducir un sistema de archivos en Linux.", "Usar 'lvextend' con un valor negativo."], respuestaCorrecta: 0, explicacion: "Reducir es peligroso. Se debe hacer fuera de línea (desmontado), verificar la integridad (fsck), reducir primero el sistema de archivos para liberar espacio, y luego el volumen lógico. Nota: XFS no soporta reducción." },
  { id: 16, curso: "Red Hat System Administration I", pregunta: "¿Qué ventaja tiene LVM cuando necesitas mover almacenamiento entre sistemas?", opciones: ["Permite usar 'pvmove' para migrar datos de un disco físico a otro en caliente, sin tiempo de inactividad.", "Obliga a copiar datos manualmente con 'cp'.", "No permite mover datos entre discos.", "Requiere apagar el sistema por horas.", "Solo funciona con discos SSD."], respuestaCorrecta: 0, explicacion: "pvmove traslada las extensiones físicas de un PV a otro dentro del mismo VG mientras el sistema está en funcionamiento, ideal para reemplazar discos fallidos o migrar a almacenamiento más rápido." },
  { id: 17, curso: "Red Hat System Administration I", pregunta: "¿Cómo identificarías si una partición está casi llena por inodos y no por espacio real?", opciones: ["Usando 'df -i', que muestra el porcentaje de uso de inodos independientemente del espacio en bloques.", "Usando 'df -h'.", "Usando 'du -sh'.", "Usando 'free -m'.", "Usando 'top'."], respuestaCorrecta: 0, explicacion: "df -i (inodes) reporta el uso de inodos. Un sistema puede tener gigabytes libres pero no poder crear archivos si se han agotado los inodos (común con millones de archivos pequeños)." },
  { id: 18, curso: "Red Hat System Administration I", pregunta: "¿Qué comando usarías para revisar el consumo de inodos y por qué importa?", opciones: ["df -i, porque si se agotan los inodos, no se podrán crear nuevos archivos o directorios, aunque haya espacio en disco disponible.", "df -h, porque muestra el espacio total.", "ls -i, porque cuenta archivos.", "inode -check, porque repara el disco.", "No es importante revisar los inodos."], respuestaCorrecta: 0, explicacion: "Cada archivo o directorio consume un inodo. El agotamiento de inodos es una causa común de fallos en servidores de correo o cachés web, donde se crean muchos archivos pequeños." },
  { id: 19, curso: "Red Hat System Administration I", pregunta: "¿Cómo detectarías un proceso que está consumiendo demasiada memoria de forma anormal?", opciones: ["Usando 'top' o 'htop' y ordenando por uso de memoria (%MEM), o 'ps aux --sort=-%mem | head'.", "Usando 'ping'.", "Revisando /var/log/messages.", "Usando 'netstat'.", "No se puede detectar sin herramientas gráficas."], respuestaCorrecta: 0, explicacion: "top, htop y ps permiten identificar rápidamente qué procesos están consumiendo la mayor cantidad de memoria RAM (columna RES o %MEM), facilitando la investigación de fugas de memoria." },
  { id: 20, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencia existe entre un proceso zombie y un proceso huérfano?", opciones: ["Zombie: terminó su ejecución pero el proceso padre no leyó su estado de salida. Huérfano: su proceso padre murió, por lo que es adoptado por init/systemd.", "Son lo mismo.", "Zombie consume mucha CPU, huérfano no.", "Huérfano es un proceso malicioso.", "Zombie es un proceso en segundo plano."], respuestaCorrecta: 0, explicacion: "Un zombie (estado Z) solo ocupa una entrada en la tabla de procesos. Un huérfano sigue ejecutándose normalmente, pero su nuevo padre es el proceso init (PID 1), que se encargará de limpiarlo cuando termine." },
  { id: 21, curso: "Red Hat System Administration I", pregunta: "¿Cómo investigarías si una tarea programada con cron no se ejecutó?", opciones: ["Revisar '/var/log/cron' o 'journalctl -u crond', verificar que el servicio esté activo, y comprobar los permisos de ejecución del script.", "Reiniciar el servidor.", "Borrar la tarea de crontab.", "Cron no falla, siempre se ejecuta.", "Revisar el historial de bash del usuario root."], respuestaCorrecta: 0, explicacion: "Los logs de cron indican si el demonio intentó ejecutar la tarea. Si aparece en el log pero no hizo nada, el problema suele ser la ruta relativa en el script, permisos o variables de entorno no cargadas." },
  { id: 22, curso: "Red Hat System Administration I", pregunta: "¿Qué ventaja tienen los systemd timers frente a cron en sistemas modernos?", opciones: ["Mejor integración con el sistema: pueden depender de que otros servicios estén activos, usan journalctl para logs centralizados y permiten mayor precisión.", "Son más fáciles de escribir que cron.", "Cron está obsoleto y no funciona en Red Hat.", "Los timers consumen más recursos.", "No tienen ventaja, son idénticos."], respuestaCorrecta: 0, explicacion: "systemd timers superan a cron al permitir condiciones complejas (ej. ejecutar solo si la red está activa), registro centralizado de errores y ejecución basada en eventos del sistema, no solo en tiempo." },
  { id: 23, curso: "Red Hat System Administration I", pregunta: "¿Cómo crearías una tarea repetitiva con systemd en lugar de cron?", opciones: ["Creando dos archivos: un archivo .service que define la acción, y un archivo .timer que define la programación y habilita el servicio.", "Editando /etc/crontab.", "Usando el comando 'systemctl add-timer'.", "No se puede, systemd no maneja tareas programadas.", "Creando un script en /etc/init.d/."], respuestaCorrecta: 0, explicacion: "La forma nativa es crear 'mi_tarea.service' (con ExecStart) y 'mi_tarea.timer' (con OnCalendar=), luego habilitar y iniciar el archivo .timer." },
  { id: 24, curso: "Red Hat System Administration I", pregunta: "¿Cómo revisarías si un sistema está sufriendo un problema de CPU alta por interrupciones o I/O wait?", opciones: ["Usando 'top' y observando los valores de 'hi' (hardware interrupts), 'si' (software interrupts) y 'wa' (iowait).", "Mirando el uso total de CPU (%us).", "Usando 'df -h'.", "Revisando el archivo /etc/cpu.", "No se puede diferenciar el tipo de uso de CPU."], respuestaCorrecta: 0, explicacion: "En la línea de resumen de 'top', 'wa' alto indica que la CPU está inactiva esperando operaciones de disco. 'hi'/'si' altos indican sobrecarga por manejo de interrupciones de red o hardware." },
  { id: 25, curso: "Red Hat System Administration I", pregunta: "¿Cómo optimizarías el arranque de un sistema revisando qué unidades tardan más en iniciar?", opciones: ["Usando 'systemd-analyze blame' para listar el tiempo de inicio de cada servicio y 'systemd-analyze critical-chain' para ver dependencias.", "Desactivando todos los servicios.", "Reinstalando el sistema operativo.", "Aumentando la memoria RAM.", "Usando 'dmesg' solamente."], respuestaCorrecta: 0, explicacion: "systemd-analyze blame ordena los servicios por tiempo de inicio. critical-chain muestra qué servicios están bloqueando el arranque de otros, permitiendo deshabilitar o enmascarar servicios innecesarios." },
  { id: 26, curso: "CCNA M3", pregunta: "¿Cómo explicarías el proceso completo de selección de la mejor ruta en una tabla de enrutamiento?", opciones: ["1. Longest Prefix Match (máscara más específica). 2. Menor Distancia Administrativa. 3. Menor Métrica del protocolo.", "1. Menor Métrica. 2. Longest Prefix Match. 3. Distancia Administrativa.", "1. Distancia Administrativa. 2. Métrica. 3. Longest Prefix Match.", "El router elige aleatoriamente entre las rutas disponibles.", "Siempre elige la ruta aprendida por OSPF."], respuestaCorrecta: 0, explicacion: "El router primero busca la coincidencia más específica de red (longest prefix). Si hay múltiples rutas para esa misma red, elige la de menor Distancia Administrativa. Si el protocolo es el mismo, elige la de menor métrica." },
  { id: 27, curso: "CCNA M3", pregunta: "¿Qué ocurre cuando un router recibe la misma red por varios protocolos distintos?", opciones: ["Instala en la tabla de enrutamiento la ruta del protocolo con la menor Distancia Administrativa.", "Instala todas las rutas y hace balanceo de carga.", "Ignora todas las rutas.", "Elige la ruta aprendida más recientemente.", "Siempre prefiere rutas estáticas sobre dinámicas sin importar la DA."], respuestaCorrecta: 0, explicacion: "La Distancia Administrativa (AD) es el criterio de desempate entre protocolos diferentes. Por ejemplo, una ruta EIGRP (AD 90) ganará a una OSPF (AD 110) para el mismo prefijo." },
  { id: 28, curso: "CCNA M3", pregunta: "¿Cómo influye la distancia administrativa en una red con rutas estáticas, OSPF y EIGRP?", opciones: ["Determina la preferencia: Estática (1) > EIGRP (90) > OSPF (110). Una ruta estática ganará a menos que se configure con una AD mayor.", "No influye, todos tienen la misma prioridad.", "OSPF siempre gana porque es el estándar.", "EIGRP siempre gana porque es de Cisco.", "La métrica es más importante que la DA."], respuestaCorrecta: 0, explicacion: "La AD es el primer filtro. Si un administrador configura una ruta estática flotante con AD 120, entonces OSPF (110) será la preferida hasta que la estática sea necesaria." },
  { id: 29, curso: "CCNA M3", pregunta: "¿Qué es redistribución de rutas y qué riesgo introduce si se configura mal?", opciones: ["Es compartir rutas de un protocolo de enrutamiento a otro. El riesgo principal es la creación de bucles de enrutamiento.", "Es resumir rutas dentro del mismo protocolo.", "Es el proceso de elegir el DR/BDR.", "Es la asignación de direcciones IP por DHCP.", "No tiene riesgos, es completamente seguro."], respuestaCorrecta: 0, explicacion: "La redistribución inyecta rutas aprendidas por un protocolo (ej. OSPF) en otro (ej. EIGRP). Sin filtros o métricas adecuadas, las rutas pueden reinyectarse, creando bucles o rutas subóptimas." },
  { id: 30, curso: "CCNA M3", pregunta: "¿Cómo evitarías bucles de enrutamiento al redistribuir entre protocolos diferentes?", opciones: ["Usando filtros de distribución (distribute-lists), route-maps con tags, o ajustando la distancia administrativa de las rutas redistribuidas.", "Aumentando el ancho de banda de los enlaces.", "Desactivando todos los protocolos dinámicos.", "Usando solo rutas estáticas.", "No se pueden evitar los bucles en la redistribución."], respuestaCorrecta: 0, explicacion: "Las route-maps permiten etiquetar rutas al redistribuir y filtrarlas en el otro lado para evitar que regresen. Aumentar la AD de las rutas redistribuidas también evita que el protocolo original las prefiera." },
  { id: 31, curso: "CCNA M3", pregunta: "¿Qué diferencias operativas hay entre sumarización manual y automática?", opciones: ["La manual se configura en límites específicos (ej. ABR) y da control total. La automática (ej. EIGRP/RIPv2) ocurre en límites de red de clase y puede ser menos precisa.", "Son idénticas en funcionamiento.", "La automática es más segura que la manual.", "La manual solo funciona con OSPF.", "La automática consume más CPU."], respuestaCorrecta: 0, explicacion: "La sumarización automática a veces crea rutas no deseadas o una ruta nula por defecto. La manual permite al ingeniero decidir exactamente qué prefijos agrupar y en qué interfaz anunciarlos." },
  { id: 32, curso: "CCNA M3", pregunta: "¿Cómo decidirías en qué punto hacer route summarization dentro de una topología jerárquica?", opciones: ["En los routers de distribución o ABRs, donde convergen múltiples subredes, para contener los cambios de topología y reducir las tablas de enrutamiento del core.", "En los routers de acceso (borde de usuario).", "En todos los routers de la red.", "Solo en el router conectado a Internet.", "La sumarización no se recomienda en topologías jerárquicas."], respuestaCorrecta: 0, explicacion: "El mejor lugar es en los límites de las áreas o bloques de direcciones. Esto limita el alcance de las actualizaciones de enrutamiento (query scope) y estabiliza la red." },
  { id: 33, curso: "CCNA M3", pregunta: "¿Qué es un área stub en OSPF y qué problema intenta reducir?", opciones: ["Un área que bloquea LSAs tipo 5 (rutas externas), reduciendo el tamaño de la base de datos y la memoria requerida en routers de recursos limitados.", "Un área que no tiene routers.", "Un área que solo usa rutas estáticas.", "Un área que no se conecta al backbone.", "Un área que bloquea todo el tráfico."], respuestaCorrecta: 0, explicacion: "Las áreas stub no reciben información de redes externas al AS (tipo 5). En su lugar, el ABR inyecta una ruta por defecto (0.0.0.0), simplificando enormemente la tabla de enrutamiento de los routers internos del área." },
  { id: 34, curso: "CCNA M3", pregunta: "¿Qué diferencia existe entre un área stub y un área totally stubby?", opciones: ["Stub bloquea tipo 5 pero permite tipo 3 (inter-área). Totally stubby bloquea tipo 3, 4 y 5, permitiendo solo una ruta por defecto del ABR.", "No hay diferencia.", "Totally stubby permite rutas externas.", "Stub es para redes pequeñas, totally stubby para grandes.", "Totally stubby no requiere ABR."], respuestaCorrecta: 0, explicacion: "Totally stubby (configuración específica de Cisco) es más restrictiva: el ABR no envía resúmenes de otras áreas (tipo 3), solo la ruta por defecto, minimizando al máximo la tabla de enrutamiento." },
  { id: 35, curso: "CCNA M3", pregunta: "¿Qué es un área NSSA y por qué se utiliza?", opciones: ["Not-So-Stubby Area: permite que un área stub tenga un ASBR local que inyecte rutas externas como LSAs tipo 7, que el ABR convierte a tipo 5.", "Un área que no soporta OSPF.", "Un área que solo usa IPv6.", "Un área que bloquea todas las rutas.", "Un área de respaldo para el backbone."], respuestaCorrecta: 0, explicacion: "NSSA resuelve la limitación del área stub (que no puede tener ASBR). Permite importar rutas externas localmente (tipo 7) sin permitir que las rutas externas de otros lugares (tipo 5) entren en el área." },
  { id: 36, curso: "CCNA M3", pregunta: "¿Qué papel cumple un ABR cuando existen varias áreas OSPF?", opciones: ["Mantiene una base de datos de enlaces (LSDB) separada para cada área conectada y genera LSAs tipo 3 para resumir y anunciar redes entre áreas.", "Solo reenvía paquetes, no participa en OSPF.", "Convierte todas las rutas en tipo 5.", "Elige el DR para todas las áreas.", "Bloquea todo el tráfico entre áreas."], respuestaCorrecta: 0, explicacion: "El ABR actúa como traductor entre áreas. Ejecuta el algoritmo SPF por separado para cada área y resume la información de topología antes de pasarla al backbone (área 0) o a otras áreas." },
  { id: 37, curso: "CCNA M3", pregunta: "¿Qué ocurre si el router ID cambia en un router OSPF ya operativo?", opciones: ["El proceso OSPF debe reiniciarse (o usar 'clear ip ospf process') para que el nuevo Router ID surta efecto, ya que se establece al inicio.", "El cambio es inmediato y sin interrupciones.", "El router se bloquea permanentemente.", "OSPF ignora el cambio.", "Se borra la configuración de OSPF."], respuestaCorrecta: 0, explicacion: "El Router ID se selecciona al iniciar el proceso OSPF. Cambiar la configuración (ej. loopback o router-id manual) no afecta al proceso en ejecución hasta que se reinicia." },
  { id: 38, curso: "CCNA M3", pregunta: "¿Cómo afecta el tipo de red OSPF al proceso de elección de DR y BDR?", opciones: ["En redes Broadcast y NBMA se elige DR/BDR. En Point-to-Point y Point-to-Multipoint no se eligen, formando adyacencias full directamente.", "Todos los tipos de red eligen DR/BDR.", "Ningún tipo de red elige DR/BDR.", "Solo Point-to-Point elige DR/BDR.", "El tipo de red no afecta la elección."], respuestaCorrecta: 0, explicacion: "DR/BDR son necesarios en redes multiacceso (como Ethernet) para reducir el número de adyacencias. En enlaces seriales punto a punto, solo hay dos routers, por lo que la elección es innecesaria." },
  { id: 39, curso: "CCNA M3", pregunta: "¿Qué tipo de red OSPF no elige DR/BDR y por qué?", opciones: ["Point-to-Point y Point-to-Multipoint, porque no hay necesidad de optimizar adyacencias en enlaces donde no hay múltiples routers compitiendo por el medio.", "Broadcast, porque es muy rápida.", "NBMA, porque no soporta multicast.", "Loopback, porque es virtual.", "Todos los tipos eligen DR/BDR."], respuestaCorrecta: 0, explicacion: "En un enlace punto a punto, solo hay dos vecinos, por lo que forman adyacencia FULL directamente sin la sobrecarga de la elección DR/BDR." },
  { id: 40, curso: "CCNA M3", pregunta: "¿Cómo diagnosticarías una vecindad OSPF que nunca llega a estado FULL?", opciones: ["Verificando coincidencia de máscaras de subred, áreas, timers (hello/dead), autenticación, y MTU en las interfaces conectadas.", "Reiniciando ambos routers.", "Cambiando el Router ID.", "Desactivando OSPF.", "Asumiendo que es un fallo de hardware."], respuestaCorrecta: 0, explicacion: "OSPF requiere parámetros idénticos para formar adyacencia. 'show ip ospf interface' y 'show ip ospf neighbor' son claves para identificar discrepancias en estos parámetros." },
  { id: 41, curso: "CCNA M3", pregunta: "¿Qué causas técnicas pueden mantener OSPF en estado EXSTART o EXCHANGE?", opciones: ["Un mismatch en el MTU de las interfaces es la causa más común, impidiendo el intercambio correcto de paquetes DBD (Database Description).", "Timers hello diferentes.", "Áreas diferentes.", "Falta de ruta por defecto.", "Router ID duplicado."], respuestaCorrecta: 0, explicacion: "En EXSTART/EXCHANGE, los routers negocian quién empieza y envían resúmenes de su base de datos. Si el MTU no coincide, los paquetes DBD se descartan y la adyacencia se estanca." },
  { id: 42, curso: "CCNA M3", pregunta: "¿Cómo identificarías si el problema de OSPF está en la máscara, el área o la autenticación?", opciones: ["Revisando los mensajes de log de OSPF ('debug ip ospf adj') o la salida de 'show ip ospf neighbor', que indica el motivo específico del fallo.", "Haciendo ping a la interfaz.", "Revisando la tabla de enrutamiento.", "Mirando el estado de la interfaz (up/up).", "No se puede identificar, es aleatorio."], respuestaCorrecta: 0, explicacion: "Los logs de OSPF son muy descriptivos. Por ejemplo, mostrarán 'mismatched hello parameters', 'area mismatch' o 'dead timer mismatch', apuntando directamente a la causa raíz." },
  { id: 43, curso: "CCNA M3", pregunta: "¿Qué es la autenticación OSPF y por qué es importante en entornos empresariales?", opciones: ["Es un mecanismo (MD5 o SHA) que asegura que los routers solo formen adyacencias con vecinos legítimos, evitando la inyección de rutas maliciosas.", "Es opcional y no tiene impacto en la seguridad.", "Solo cifra el tráfico de usuario.", "Es un firewall integrado.", "Aumenta la velocidad de convergencia."], respuestaCorrecta: 0, explicacion: "Sin autenticación, un atacante podría conectar un router no autorizado a la red y enviar LSAs falsos, desviando o interrumpiendo el tráfico de la empresa." },
  { id: 44, curso: "CCNA M3", pregunta: "¿Cómo configurarías y verificarías autenticación entre vecinos OSPF?", opciones: ["Configurando 'ip ospf authentication message-digest' y 'ip ospf message-digest-key' en la interfaz, y verificando con 'show ip ospf neighbor'.", "Usando 'ospf auth' en modo global.", "La autenticación se habilita automáticamente.", "Usando contraseñas en clear text siempre.", "No se puede verificar."], respuestaCorrecta: 0, explicacion: "La autenticación debe coincidir en ambos lados del enlace. 'show ip ospf neighbor' confirmará que la adyacencia llega a FULL, indicando que la autenticación fue exitosa." },
  { id: 45, curso: "CCNA M3", pregunta: "¿Qué impacto tiene el costo OSPF en el balanceo de carga de rutas de igual costo?", opciones: ["Si OSPF calcula el mismo costo total para múltiples rutas hacia un destino, instalará todas en la tabla de enrutamiento (ECMP), permitiendo balanceo de carga.", "OSPF no soporta balanceo de carga.", "El costo no afecta el balanceo.", "Solo balancea si las rutas son de diferentes protocolos.", "El balanceo de carga desactiva OSPF."], respuestaCorrecta: 0, explicacion: "ECMP (Equal-Cost Multi-Path) es nativo en OSPF. Si hay dos enlaces de 1Gbps hacia el mismo destino, el costo es idéntico y el router distribuirá el tráfico entre ambos." },
  { id: 46, curso: "CCNA M3", pregunta: "¿Qué diferencia hay entre balanceo de carga de costo igual y costo desigual?", opciones: ["Costo igual (ECMP) es nativo en OSPF/EIGRP. Costo desigual es exclusivo de EIGRP (usando el comando 'variance'), permitiendo usar rutas de respaldo con métrica mayor.", "Son lo mismo.", "Costo desigual es más común en OSPF.", "Costo igual solo funciona con rutas estáticas.", "Ningún protocolo soporta costo desigual."], respuestaCorrecta: 0, explicacion: "OSPF solo balancea si el costo es idéntico. EIGRP puede balancear de forma desigual si la métrica de la ruta alternativa es menor que la métrica de la mejor ruta multiplicada por el valor de 'variance'." },
  { id: 47, curso: "CCNA M3", pregunta: "¿Cómo interpretarías la salida de 'show ip ospf database' para detectar problemas de convergencia?", opciones: ["Buscando LSAs con números de secuencia inusualmente altos (indicando inestabilidad/flapping) o la ausencia de LSAs esperados de un ABR/ASBR.", "Mirando la dirección IP del router.", "Contando el número total de interfaces.", "La base de datos no muestra problemas de convergencia.", "Buscando errores de sintaxis."], respuestaCorrecta: 0, explicacion: "Un número de secuencia que aumenta rápidamente indica que un enlace o router está inestable (flapping), lo que fuerza a la red a recalcular constantemente, consumiendo CPU y afectando la convergencia." },
  { id: 48, curso: "CCNA M3", pregunta: "¿Qué es un LSA tipo 1, tipo 2, tipo 3 y tipo 5 en OSPF?", opciones: ["Tipo 1: Router (dentro del área). Tipo 2: Network (DR). Tipo 3: Summary (inter-área, por ABR). Tipo 5: AS External (rutas externas, por ASBR).", "Tipo 1: Externo. Tipo 2: Interno. Tipo 3: Backup. Tipo 5: Principal.", "Todos son iguales, solo cambia el número.", "Tipo 1 es para IPv6, Tipo 2 para IPv4.", "No existen LSAs tipo 5."], respuestaCorrecta: 0, explicacion: "Cada tipo de LSA tiene una función específica en la construcción del mapa de topología: 1 y 2 son intra-área, 3 conecta áreas, y 5 trae rutas de fuera del sistema autónomo OSPF." },
  { id: 49, curso: "CCNA M3", pregunta: "¿Cómo cambia la base de datos OSPF cuando un router se convierte en ABR?", opciones: ["Comienza a generar LSAs tipo 3 (Summary LSA) para anunciar las redes de un área hacia el backbone y viceversa.", "Deja de generar LSAs tipo 1.", "Borra toda la base de datos.", "Se convierte automáticamente en ASBR.", "No hay ningún cambio en la base de datos."], respuestaCorrecta: 0, explicacion: "Al conectar dos áreas, el router mantiene dos LSDBs separadas y asume el rol de traducir la información de topología de un área a resúmenes (tipo 3) para la otra." },
  { id: 50, curso: "CCNA M3", pregunta: "¿Qué ventaja tiene la convergencia rápida frente a la estabilidad de la red en un diseño bien hecho?", opciones: ["En un diseño bien hecho, la convergencia rápida es una ventaja porque minimiza el tiempo de inactividad, y la estabilidad se logra mediante sumarización y filtrado, no ralentizando la convergencia.", "La estabilidad siempre es más importante que la convergencia rápida.", "La convergencia rápida causa inestabilidad.", "No hay relación entre convergencia y estabilidad.", "La convergencia rápida solo funciona en redes pequeñas."], respuestaCorrecta: 0, explicacion: "El objetivo es tener ambos. Un diseño jerárquico con sumarización limita el alcance de los cambios (estabilidad), permitiendo que los protocolos reaccionen rápidamente (convergencia) solo donde es necesario." },
  { id: 51, curso: "CCNA M3", pregunta: "¿Cómo reaccionaría una red OSPF ante la caída de un enlace crítico entre áreas?", opciones: ["Los ABRs detectarían el fallo, generarían nuevos LSAs, y el tráfico se redirigiría por enlaces de respaldo si existen, o se perdería la conectividad entre esas áreas.", "La red se reiniciaría completamente.", "OSPF dejaría de funcionar en todas las áreas.", "El router principal se convertiría en un switch.", "No pasaría nada, el tráfico se pierde silenciosamente."], respuestaCorrecta: 0, explicacion: "OSPF reacciona enviando actualizaciones de estado de enlace. Si hay redundancia, el algoritmo SPF recalcula y la tabla de enrutamiento se actualiza. Si no, las áreas quedan aisladas." },
  { id: 52, curso: "CCNA M3", pregunta: "¿Qué es route poisoning o invalidación de rutas en protocolos de vector distancia y cómo se compara con OSPF?", opciones: ["En vector distancia (ej. RIP), se anuncia la red con métrica infinita (16) para indicar que es inalcanzable. OSPF simplemente retira el LSA o incrementa su secuencia, sin usar métrica infinita.", "OSPF también usa métrica infinita.", "Route poisoning solo existe en OSPF.", "Vector distancia no usa route poisoning.", "Son mecanismos idénticos."], respuestaCorrecta: 0, explicacion: "RIP usa 16 como infinito. OSPF, al ser estado de enlace, no necesita 'envenenar' la ruta; simplemente elimina el LSA de la base de datos o lo reemplaza con uno nuevo que no contiene ese enlace, y todos recalculan." },
  { id: 53, curso: "CCNA M3", pregunta: "¿Cómo resolverías un problema de ruta asimétrica en una topología con múltiples caminos?", opciones: ["Ajustando los costos de las interfaces OSPF para que el camino de ida y vuelta sea el mismo, o configurando PBR (Policy-Based Routing) si se requiere un flujo específico.", "Desactivando todos los caminos menos uno.", "Ruta asimétrica no es un problema, siempre es deseable.", "Cambiando las direcciones IP de los routers.", "Usando solo rutas estáticas."], respuestaCorrecta: 0, explicacion: "La asimetría puede romper firewalls stateful o causar problemas de QoS. Alinear los costos OSPF asegura que el camino más corto sea el mismo en ambas direcciones." },
  { id: 54, curso: "CCNA M3", pregunta: "¿Qué diferencia existe entre una ruta flotante y una ruta de respaldo con tracking?", opciones: ["Ruta flotante: usa una Distancia Administrativa alta y siempre está en la tabla (pero no se usa). Tracking: la ruta se elimina de la tabla si un objeto IP SLA (ej. ping) falla.", "Son exactamente lo mismo.", "Tracking usa DA alta, flotante usa SLA.", "Ruta flotante es dinámica, tracking es estática.", "Ninguna de las dos proporciona respaldo."], respuestaCorrecta: 0, explicacion: "La ruta flotante es pasiva (espera a que la ruta principal desaparezca). El tracking es proactivo: monitorea la viabilidad real del next-hop y retira la ruta antes de que el protocolo de enrutamiento detecte el fallo." },
  { id: 55, curso: "CCNA M3", pregunta: "¿Cómo usarías IP SLA para supervisar una ruta estática de respaldo?", opciones: ["Configurando un objeto IP SLA (ej. echo a un destino), un objeto 'track' que monitoree el SLA, y vinculando la ruta estática a ese track con el comando 'track'.", "IP SLA no se puede vincular a rutas estáticas.", "Usando 'ping' manual cada minuto.", "Configurando OSPF en lugar de estática.", "IP SLA solo funciona con BGP."], respuestaCorrecta: 0, explicacion: "La sintaxis es: 'ip sla', 'track <id> ip sla <id> reachability', y 'ip route <destino> <mascara> <next-hop> track <id>'. Si el track falla, la ruta estática se retira." },
  { id: 56, curso: "CCNA M3", pregunta: "¿Cómo identificarías una fuga de rutas por mala filtración en un router de borde?", opciones: ["Revisando la tabla de enrutamiento de vecinos externos (o usando looking glasses) para ver si se están anunciando prefijos privados o internos que no deberían salir.", "Revisando los logs locales del router.", "Haciendo ping a Internet.", "La fuga de rutas no se puede identificar.", "Revisando la configuración de VLAN."], respuestaCorrecta: 0, explicacion: "Una fuga de rutas ocurre cuando un router de borde anuncia redes internas a Internet o a un cliente. Se detecta verificando los anuncios salientes (neighbor advertised-routes) o consultando bases de datos públicas de enrutamiento." },
  { id: 57, curso: "CCNA M3", pregunta: "¿Qué problema genera anunciar demasiadas redes específicas en una red grande?", opciones: ["Infla las tablas de enrutamiento globales, consume memoria y CPU en todos los routers, y ralentiza la convergencia ante cambios.", "Mejora la precisión del enrutamiento.", "No genera ningún problema.", "Aumenta la seguridad de la red.", "Reduce el uso de ancho de banda."], respuestaCorrecta: 0, explicacion: "Cada prefijo específico consume una entrada en la tabla de enrutamiento (FIB) y debe ser procesado. La falta de sumarización es una de las principales causas de inestabilidad en redes grandes." },
  { id: 58, curso: "CCNA M3", pregunta: "¿Cómo afectaría una mala segmentación al tamaño de la tabla de enrutamiento?", opciones: ["Si las subredes no se pueden agrupar (sumarizar) de forma contigua, el router debe anunciar cada subred individualmente, inflando la tabla.", "La segmentación no afecta la tabla de enrutamiento.", "Una mala segmentación reduce el tamaño de la tabla.", "Solo afecta a la capa 2.", "Mejora la convergencia."], respuestaCorrecta: 0, explicacion: "Para sumarizar eficientemente, las subredes deben ser contiguas y diseñadas jerárquicamente. Una asignación aleatoria de IPs impide la sumarización, forzando anuncios específicos." },
  { id: 59, curso: "CCNA M3", pregunta: "¿Qué significa que un router sea el ASBR en un entorno OSPF?", opciones: ["Que es un Autonomous System Boundary Router, encargado de inyectar rutas externas (de otros protocolos o AS) en el dominio OSPF como LSAs tipo 5 o 7.", "Que es el router principal del área 0.", "Que solo maneja tráfico interno.", "Que no participa en OSPF.", "Que es un switch de capa 3."], respuestaCorrecta: 0, explicacion: "El ASBR actúa como puerta de enlace entre OSPF y el mundo exterior (ej. redistribuyendo desde BGP o EIGRP), generando LSAs externos que el resto del dominio OSPF debe procesar." },
  { id: 60, curso: "CCNA M3", pregunta: "¿Cómo distinguirías un problema de capa 3 local de una falla de enrutamiento inter-área?", opciones: ["Si puedes hacer ping al gateway por defecto pero no a redes remotas, es un problema de enrutamiento (capa 3 inter-área). Si no puedes hacer ping ni al gateway, el problema es local (capa 2 o IP local).", "No se pueden distinguir.", "Siempre es un problema de capa 2.", "Siempre es un problema de enrutamiento.", "Usando solo 'show version'."], respuestaCorrecta: 0, explicacion: "El ping al gateway prueba la conectividad local (ARP, VLAN, interfaz up). El ping a una red remota prueba la tabla de enrutamiento y la ruta a través de la red. Aislar el punto de fallo es clave." },
  { id: 61, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué problema resuelve la modularización del código en un proyecto web grande?", opciones: ["Evita el 'spaghetti code', facilita el mantenimiento, permite la reutilización de componentes y mejora la capacidad de trabajo en equipo.", "Hace que el código sea más difícil de leer.", "Aumenta el tamaño del archivo final.", "Obliga a usar un solo archivo.", "No resuelve ningún problema real."], respuestaCorrecta: 0, explicacion: "Dividir el código en módulos o componentes independientes permite que los desarrolladores trabajen en partes aisladas, facilitando las pruebas unitarias y la depuración." },
  { id: 62, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cuál es la diferencia entre arquitectura monolítica y arquitectura basada en componentes?", opciones: ["Monolítica: toda la lógica y UI están acopladas en un solo bloque. Basada en componentes: la UI se divide en piezas reutilizables, independientes y con estado propio.", "Son lo mismo.", "La monolítica es más moderna.", "La basada en componentes solo funciona en el servidor.", "La monolítica es más fácil de escalar."], respuestaCorrecta: 0, explicacion: "Frameworks como React, Vue o Angular se basan en componentes, lo que permite construir interfaces complejas ensamblando bloques pequeños y probables, a diferencia de un archivo HTML/JS gigante." },
  { id: 63, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una SPA y qué ventajas y desventajas tiene frente a un sitio multipágina?", opciones: ["Single Page Application: carga una sola vez y actualiza el contenido dinámicamente. Ventaja: UX fluida. Desventaja: SEO inicial más complejo y mayor carga de JS inicial.", "Sitio que solo tiene una página HTML sin interactividad.", "Ventaja: mejor SEO. Desventaja: recargas constantes.", "Es lo mismo que un sitio multipágina.", "Ventaja: no requiere JavaScript."], respuestaCorrecta: 0, explicacion: "Las SPAs ofrecen una experiencia similar a una app de escritorio, pero requieren que el navegador descargue todo el framework JS al inicio, y el SEO requiere técnicas como SSR o pre-rendering." },
  { id: 64, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cómo funciona el enrutamiento del lado del cliente en una SPA?", opciones: ["Intercepta los clics en los enlaces, previene la recarga del navegador, actualiza la URL usando la History API y renderiza el componente correspondiente.", "Recarga la página completa en cada clic.", "Usa el enrutamiento del servidor Apache/Nginx.", "Cambia la URL pero no muestra nada nuevo.", "No existe el enrutamiento del lado del cliente."], respuestaCorrecta: 0, explicacion: "Librerías como React Router usan 'pushState' para cambiar la URL sin recargar, y luego escuchan ese cambio para mostrar el componente adecuado, simulando la navegación." },
  { id: 65, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es el ciclo de vida de un componente en una aplicación web moderna?", opciones: ["Las fases por las que pasa un componente: Montaje (creación), Actualización (cambio de props/estado) y Desmontaje (eliminación del DOM).", "El tiempo que tarda en cargarse la página.", "El proceso de compilación del código.", "La conexión a la base de datos.", "No existe ciclo de vida en componentes."], respuestaCorrecta: 0, explicacion: "Entender el ciclo de vida es crucial para ejecutar efectos secundarios (como peticiones a API) en el momento correcto (ej. 'useEffect' en React o 'mounted' en Vue) y limpiar recursos al desmontar." },
  { id: 66, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia existe entre estado local y estado global en una interfaz web?", opciones: ["Estado local: solo afecta y es accesible dentro del componente. Estado global: es accesible por cualquier parte de la aplicación (ej. Redux, Context API).", "No hay diferencia.", "Estado global es más rápido que el local.", "Estado local se guarda en el servidor.", "Estado global solo funciona con bases de datos."], respuestaCorrecta: 0, explicacion: "El estado local (ej. 'useState') es ideal para datos de UI específicos (como un input abierto). El estado global se usa para datos compartidos (como la información del usuario autenticado)." },
  { id: 67, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una closure en JavaScript y por qué es útil?", opciones: ["Una función que recuerda y accede a las variables de su ámbito léxico externo, incluso después de que la función externa haya terminado de ejecutarse.", "Un error de sintaxis.", "Una forma de cerrar el navegador.", "Un bucle infinito.", "Una variable global."], respuestaCorrecta: 0, explicacion: "Las closures son fundamentales para la encapsulación de datos, la creación de funciones fábrica y el funcionamiento de callbacks y promesas, permitiendo que las funciones 'recuerden' su entorno." },
  { id: 68, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cómo explicarías el comportamiento de 'this' en distintos contextos de JavaScript?", opciones: ["Depende de cómo se llama la función: en un método de objeto apunta al objeto, en una función normal apunta al global (o undefined en strict mode), y en una función flecha hereda el 'this' del contexto donde fue definida.", "Siempre apunta al objeto global window.", "Siempre apunta a la función misma.", "No se puede predecir.", "Es lo mismo que en Java."], respuestaCorrecta: 0, explicacion: "El valor de 'this' es dinámico en funciones tradicionales (binding implícito, explícito con call/apply/bind), pero es léxico (estático) en las funciones flecha, lo que evita muchos errores comunes en callbacks." },
  { id: 69, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre programación síncrona y asíncrona en el navegador?", opciones: ["Síncrona: bloquea el hilo principal hasta que la operación termina. Asíncrona: permite que el navegador siga ejecutando código mientras espera una operación (como una petición de red).", "Síncrona es más rápida siempre.", "Asíncrona bloquea el hilo principal.", "No hay diferencia.", "Síncrona solo funciona con bases de datos."], respuestaCorrecta: 0, explicacion: "JavaScript es single-threaded. Las operaciones asíncronas (fetch, setTimeout) se delegan a las APIs del navegador y su resultado se maneja después a través del Event Loop, evitando congelar la interfaz." },
  { id: 70, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cómo funciona el event loop de JavaScript a alto nivel?", opciones: ["Monitoriza el Call Stack y la Task Queue. Si el Call Stack está vacío, toma la primera tarea de la Queue y la empuja al Stack para su ejecución.", "Ejecuta todo el código en paralelo.", "Detiene la ejecución del código hasta que se resuelven las promesas.", "Es un bucle for infinito.", "No existe en JavaScript."], respuestaCorrecta: 0, explicacion: "El Event Loop es el mecanismo que permite a JavaScript realizar operaciones no bloqueantes. Mueve callbacks de la cola al stack solo cuando el stack está completamente vacío." },
  { id: 71, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué problema resuelve Promise.all() y cuándo no conviene usarlo?", opciones: ["Resuelve: ejecutar múltiples promesas en paralelo y esperar a que todas terminen. No conviene: si una falla, todas fallan (fail-fast), o si las peticiones son independientes y una falla no debería cancelar las demás.", "Resuelve: ejecutar promesas en secuencia.", "No tiene problemas, siempre es la mejor opción.", "No conviene usarlo nunca.", "Resuelve: cancelar promesas."], respuestaCorrecta: 0, explicacion: "Promise.all es ideal cuando necesitas todos los resultados para continuar. Si las peticiones son independientes, es mejor usar Promise.allSettled() o manejarlas individualmente para evitar que un fallo parcial rompa todo el flujo." },
  { id: 72, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre async/await y encadenar promesas?", opciones: ["Async/await es azúcar sintáctica que hace que el código asíncrono se lea como síncrono, facilitando el manejo de errores con try/catch. El encadenamiento (.then) puede volverse anidado y menos legible.", "Son exactamente lo mismo.", "Async/await es más lento.", "El encadenamiento no permite manejar errores.", "Async/await solo funciona con arrays."], respuestaCorrecta: 0, explicacion: "Aunque ambos usan promesas por debajo, async/await mejora drásticamente la legibilidad y el flujo de control, especialmente al manejar múltiples pasos asíncronos o bucles." },
  { id: 73, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es CORS y por qué existe en aplicaciones web modernas?", opciones: ["Cross-Origin Resource Sharing: es un mecanismo de seguridad del navegador que restringe las peticiones HTTP a dominios distintos al origen para prevenir ataques.", "Es un protocolo de enrutamiento.", "Es una librería de JavaScript.", "Es un método para acelerar la carga de imágenes.", "No tiene relación con la seguridad."], respuestaCorrecta: 0, explicacion: "CORS protege a los usuarios evitando que un sitio web malicioso haga peticiones a otro sitio (ej. tu banco) en nombre del usuario sin su consentimiento explícito." },
  { id: 74, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cómo resolverías un error de CORS sin desactivar la seguridad del navegador?", opciones: ["Configurando el servidor backend para que envíe los headers HTTP adecuados, como 'Access-Control-Allow-Origin' con el dominio del frontend.", "Desinstalando el navegador.", "Usando una extensión del navegador para desactivar CORS.", "Cambiando el código del frontend para ignorar el error.", "No se puede resolver, es un error del navegador."], respuestaCorrecta: 0, explicacion: "CORS es una restricción del navegador, no del servidor. La solución correcta es que el servidor autorice explícitamente al origen del frontend mediante headers, no desactivar la seguridad del cliente." },
  { id: 75, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una cookie HttpOnly y por qué mejora la seguridad?", opciones: ["Es una cookie que no puede ser accedida mediante JavaScript (document.cookie), lo que previene que ataques XSS roben tokens de sesión.", "Es una cookie que solo funciona en HTTP, no en HTTPS.", "Es una cookie que se borra al cerrar el navegador.", "Es una cookie que acelera la carga.", "No tiene impacto en la seguridad."], respuestaCorrecta: 0, explicacion: "Al marcar una cookie como HttpOnly, el navegador impide que cualquier script del lado del cliente la lea, protegiendo la sesión del usuario incluso si se ejecuta código malicioso inyectado." },
  { id: 76, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre localStorage, sessionStorage y cookies?", opciones: ["localStorage: persistente hasta que se borre. sessionStorage: se borra al cerrar la pestaña. Cookies: se envían en cada petición HTTP al servidor y tienen límite de tamaño.", "Son tres nombres para lo mismo.", "Cookies son más grandes que localStorage.", "localStorage se envía al servidor automáticamente.", "sessionStorage es persistente."], respuestaCorrecta: 0, explicacion: "Cada uno tiene un caso de uso: localStorage para preferencias de usuario a largo plazo, sessionStorage para datos de una sesión de navegación, y cookies para autenticación y seguimiento del servidor." },
  { id: 77, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es XSS y cómo se previene en una aplicación web?", opciones: ["Cross-Site Scripting: inyección de scripts maliciosos. Se previene sanitizando inputs, usando textContent en lugar de innerHTML, e implementando Content Security Policy (CSP).", "Es un error de sintaxis. Se previene usando un linter.", "Es un ataque de red. Se previene con un firewall.", "Es un problema de base de datos. Se previene con índices.", "No se puede prevenir."], respuestaCorrecta: 0, explicacion: "XSS ocurre cuando la aplicación muestra datos del usuario sin escapar. La defensa en profundidad incluye validación, escape de salida y headers CSP que restringen la ejecución de scripts no autorizados." },
  { id: 78, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es CSRF y qué medidas ayudan a evitarlo?", opciones: ["Cross-Site Request Forgery: engañar al usuario para que ejecute acciones no deseadas en un sitio donde está autenticado. Se evita con tokens anti-CSRF y atributos SameSite en cookies.", "Es lo mismo que XSS.", "Es un ataque de denegación de servicio.", "Se evita usando contraseñas largas.", "No tiene medidas de prevención."], respuestaCorrecta: 0, explicacion: "CSRF explota la confianza del sitio en el navegador del usuario. Los tokens anti-CSRF aseguran que la petición fue generada intencionalmente por la aplicación, y SameSite impide que las cookies se envíen en peticiones cross-site." },
  { id: 79, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencias hay entre autenticación con sesión y autenticación con token?", opciones: ["Sesión: el estado se guarda en el servidor, el cliente solo tiene un ID de sesión en cookie. Token (ej. JWT): el estado se guarda en el cliente, el token está firmado criptográficamente y el servidor no guarda estado.", "Son idénticas.", "La sesión es más escalable que el token.", "El token requiere base de datos en el servidor.", "La sesión no usa cookies."], respuestaCorrecta: 0, explicacion: "La autenticación por sesión es stateful (el servidor debe recordar al usuario). La de token es stateless (el servidor solo verifica la firma del token), lo que facilita la escalabilidad horizontal." },
  { id: 80, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es JWT y cuáles son sus riesgos si se implementa mal?", opciones: ["JSON Web Token: un token firmado que contiene datos (claims). Riesgos: almacenarlo en localStorage (vulnerable a XSS), no validar la firma en el servidor, o usar algoritmos débiles.", "Es un tipo de base de datos.", "No tiene riesgos, es 100% seguro.", "Es un protocolo de red.", "El riesgo principal es que es muy grande."], respuestaCorrecta: 0, explicacion: "Si un JWT es robado (ej. por XSS), el atacante puede suplantar al usuario hasta que expire. Por eso, a menudo se recomienda almacenarlo en cookies HttpOnly en lugar de localStorage." },
  { id: 81, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué papel juegan los headers HTTP en rendimiento y seguridad?", opciones: ["Rendimiento: Cache-Control, Compression. Seguridad: Strict-Transport-Security (HSTS), Content-Security-Policy (CSP), X-Frame-Options.", "No juegan ningún papel.", "Solo sirven para indicar el tipo de contenido.", "Son irrelevantes para la seguridad.", "Solo afectan al SEO."], respuestaCorrecta: 0, explicacion: "Los headers son instrucciones cruciales que el servidor envía al navegador para dictar cómo manejar la caché, si forzar HTTPS, o qué recursos pueden ser cargados, impactando directamente en velocidad y seguridad." },
  { id: 82, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre caché del navegador y caché del servidor?", opciones: ["Caché del navegador: almacena recursos (imágenes, CSS) localmente en el dispositivo del usuario. Caché del servidor: almacena respuestas de base de datos o API en memoria (ej. Redis) para servir rápido a todos los usuarios.", "Son lo mismo.", "La caché del navegador es más rápida para el servidor.", "La caché del servidor solo funciona con imágenes.", "No existe la caché del servidor."], respuestaCorrecta: 0, explicacion: "Ambas son complementarias. La caché del servidor reduce la carga en la base de datos, y la caché del navegador reduce las peticiones de red y el tiempo de carga percibido por el usuario." },
  { id: 83, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué significa compresión gzip o brotli para una web?", opciones: ["Algoritmos que comprimen archivos de texto (HTML, CSS, JS) en el servidor antes de enviarlos, reduciendo drásticamente el tamaño de la transferencia y mejorando la velocidad.", "Formas de cifrar la base de datos.", "Técnicas para comprimir imágenes.", "Métodos para ofuscar el código JavaScript.", "Protocolos de autenticación."], respuestaCorrecta: 0, explicacion: "Brotli es generalmente más eficiente que gzip. El navegador descomprime los archivos al recibirlos. Es una de las optimizaciones de rendimiento más efectivas y fáciles de implementar." },
  { id: 84, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cómo impacta el tamaño de imágenes y recursos en la velocidad de carga?", opciones: ["Impacta directamente en métricas como LCP (Largest Contentful Paint). Imágenes no optimizadas son la causa principal de sitios web lentos.", "No tiene impacto, los navegadores son muy rápidos.", "Solo afecta a los sitios de comercio electrónico.", "Mejora la calidad visual sin afectar la velocidad.", "El tamaño no importa, solo el formato."], respuestaCorrecta: 0, explicacion: "Las imágenes suelen representar el mayor porcentaje del peso de una página. Usar formatos modernos (WebP, AVIF) y dimensiones adecuadas es crítico para el rendimiento y el SEO." },
  { id: 85, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es lazy loading y cuándo conviene aplicarlo?", opciones: ["Es la técnica de cargar recursos (imágenes, componentes, scripts) solo cuando están a punto de ser visibles en el viewport. Conviene en páginas largas con muchos medios.", "Es cargar todo al inicio para que sea más rápido.", "Es una técnica de seguridad.", "Es un método de enrutamiento.", "No se recomienda en ninguna situación."], respuestaCorrecta: 0, explicacion: "Lazy loading mejora el tiempo de carga inicial y ahorra ancho de banda, ya que no se descargan recursos que el usuario podría nunca ver si no hace scroll." },
  { id: 86, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre renderizado en cliente y renderizado en servidor?", opciones: ["Cliente: el navegador descarga un HTML vacío y JavaScript construye el DOM. Servidor: el servidor genera el HTML completo con datos y lo envía al navegador.", "Son lo mismo.", "Cliente es más rápido para el SEO.", "Servidor requiere más JavaScript en el cliente.", "Cliente no usa JavaScript."], respuestaCorrecta: 0, explicacion: "El renderizado en servidor (SSR) mejora el SEO y la velocidad de carga inicial percibida, mientras que el renderizado en cliente (CSR) ofrece una interactividad más fluida después de la carga inicial." },
  { id: 87, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es SSR y por qué se usa en ciertos proyectos?", opciones: ["Server-Side Rendering. Se usa para mejorar el SEO (los bots ven el contenido inmediatamente), la velocidad de carga inicial y el rendimiento en dispositivos de gama baja.", "Es un tipo de base de datos.", "Es un framework de CSS.", "Se usa solo para aplicaciones de escritorio.", "No tiene ventajas sobre el renderizado en cliente."], respuestaCorrecta: 0, explicacion: "Frameworks como Next.js o Nuxt.js facilitan el SSR, combinando las ventajas del SEO y la carga rápida del servidor con la interactividad del cliente." },
  { id: 88, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una API REST bien diseñada?", opciones: ["Usa recursos plurales en las URLs, métodos HTTP correctos (GET, POST, PUT, DELETE), códigos de estado adecuados, y es stateless.", "Usa verbos en las URLs (ej. /getUser).", "Devuelve siempre código 200 incluso en errores.", "Requiere que el cliente mantenga la sesión en el servidor.", "No usa JSON."], respuestaCorrecta: 0, explicacion: "Una API RESTful sigue convenciones que la hacen predecible y fácil de usar: sustantivos para recursos, verbos HTTP para acciones, y códigos de estado que reflejan el resultado real de la operación." },
  { id: 89, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre idempotencia y no idempotencia en métodos HTTP?", opciones: ["Idempotente: hacer la misma petición múltiples veces tiene el mismo efecto que hacerla una vez (GET, PUT, DELETE). No idempotente: cada petición crea un nuevo estado (POST).", "No hay diferencia.", "Idempotente significa que es más rápido.", "No idempotente es más seguro.", "Todos los métodos HTTP son idempotentes."], respuestaCorrecta: 0, explicacion: "La idempotencia es crucial para la tolerancia a fallos. Si una petición PUT falla por timeout, el cliente puede reintentarla de forma segura sin crear duplicados, a diferencia de POST." },
  { id: 90, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cómo diseñarías un formulario web robusto con validación, accesibilidad y seguridad?", opciones: ["Validación en cliente (HTML5/JS) y servidor, etiquetas <label> asociadas, atributos ARIA, sanitización de inputs, token CSRF y feedback claro al usuario.", "Solo validación en el servidor.", "Usar solo JavaScript, sin HTML.", "Sin validación para no molestar al usuario.", "Ocultar los campos de contraseña en texto plano."], respuestaCorrecta: 0, explicacion: "Un formulario robusto debe ser usable (accesible), seguro (protegido contra inyección y CSRF) y resiliente (validación en ambos lados para UX y seguridad)." },
  { id: 91, curso: "Algoritmia", pregunta: "¿Cómo demostrarías la corrección de un algoritmo mediante invariantes de ciclo?", opciones: ["Demostrando que una condición es verdadera antes de la primera iteración, se mantiene verdadera después de cada iteración, y al finalizar implica la corrección del resultado.", "Ejecutando el algoritmo con mil casos de prueba.", "Contando el número de líneas de código.", "Asumiendo que funciona si no da error.", "Usando un compilador más moderno."], respuestaCorrecta: 0, explicacion: "Un invariante de ciclo es una propiedad formal que, si se cumple al inicio, se preserva en cada paso y, al terminar el ciclo, garantiza que el algoritmo ha resuelto el problema correctamente." },
  { id: 92, curso: "Algoritmia", pregunta: "¿Qué es una prueba de terminación en un algoritmo recursivo?", opciones: ["Demostrar que existe una métrica (como el tamaño del problema) que disminuye estrictamente en cada llamada recursiva hasta alcanzar el caso base.", "Demostrar que el algoritmo usa poca memoria.", "Demostrar que el algoritmo es iterativo.", "Asegurar que no haya bucles infinitos en el código.", "No es necesario probar la terminación."], respuestaCorrecta: 0, explicacion: "Para evitar la recursión infinita, se debe probar que cada llamada se acerca al caso base (ej. n se reduce a n-1), garantizando que el proceso terminará en un número finito de pasos." },
  { id: 93, curso: "Algoritmia", pregunta: "¿Cómo analizarías la complejidad de un algoritmo recursivo usando árbol de recurrencia?", opciones: ["Dibujando el árbol de llamadas, calculando el trabajo realizado en cada nivel y sumando los niveles (a menudo aplicando el Teorema Maestro).", "Contando solo las llamadas a la función.", "Ignorando las llamadas recursivas.", "Midiendo el tiempo de ejecución con un cronómetro.", "El árbol de recurrencia solo sirve para algoritmos iterativos."], respuestaCorrecta: 0, explicacion: "El árbol de recurrencia visualiza cómo se divide el problema. Sumar el costo de cada nivel permite derivar la complejidad total, siendo la base formal del Teorema Maestro." },
  { id: 94, curso: "Algoritmia", pregunta: "¿Qué diferencia hay entre una solución greedy correcta y una que solo parece eficiente?", opciones: ["La correcta cumple matemáticamente con la propiedad de elección greedy y subestructura óptima. La que solo parece eficiente puede fallar en casos borde y no garantizar la solución óptima global.", "No hay diferencia, ambas son válidas.", "La que parece eficiente es siempre mejor.", "La correcta es más lenta.", "Greedy nunca es correcto."], respuestaCorrecta: 0, explicacion: "Un algoritmo voraz no funciona para todos los problemas. Debe demostrarse que tomar la mejor decisión local en cada paso conduce inevitablemente a la mejor decisión global (ej. Árbol de Expansión Mínima)." },
  { id: 95, curso: "Algoritmia", pregunta: "¿Cómo identificarías si un problema admite programación dinámica?", opciones: ["Si tiene subproblemas superpuestos (se resuelven múltiples veces) y subestructura óptima (la solución óptima del problema contiene soluciones óptimas de subproblemas).", "Si el problema es muy pequeño.", "Si el problema se puede resolver con un solo bucle for.", "Si el problema no tiene solución.", "Si usa recursión, automáticamente es programación dinámica."], respuestaCorrecta: 0, explicacion: "Estas dos propiedades son la señal definitiva. Si los subproblemas son independientes (como en Divide y Vencerás), la programación dinámica no aporta ventaja." },
  { id: 96, curso: "Algoritmia", pregunta: "¿Qué diferencia existe entre memoización y tabulación?", opciones: ["Memoización: enfoque top-down, recursivo, calcula y almacena resultados bajo demanda. Tabulación: enfoque bottom-up, iterativo, llena una tabla desde los casos base hasta el problema final.", "Son exactamente lo mismo.", "Memoización usa menos memoria siempre.", "Tabulación es recursiva.", "Memoización no almacena resultados."], respuestaCorrecta: 0, explicacion: "Ambas son técnicas de programación dinámica. La memoización evita calcular lo que no se necesita, pero tiene overhead de recursión. La tabulación es iterativa y a menudo más eficiente en espacio y tiempo, pero calcula todo." },
  { id: 97, curso: "Algoritmia", pregunta: "¿Qué es subestructura óptima y por qué importa?", opciones: ["Significa que la solución óptima al problema principal se puede construir a partir de las soluciones óptimas de sus subproblemas. Es el requisito fundamental para usar DP o algoritmos voraces.", "Significa que el código está bien indentado.", "Significa que el algoritmo es rápido.", "Es irrelevante para el diseño de algoritmos.", "Significa que no hay subproblemas."], respuestaCorrecta: 0, explicacion: "Sin subestructura óptima, no podemos construir la solución global a partir de partes. Por ejemplo, el camino más corto tiene esta propiedad, pero el camino más largo simple no la tiene." },
  { id: 98, curso: "Algoritmia", pregunta: "¿Cómo resolverías un problema de mochila 0/1 con programación dinámica?", opciones: ["Usando una matriz 2D donde dp[i][w] representa el valor máximo obtenible con los primeros 'i' elementos y una capacidad de peso 'w', llenándola de forma iterativa.", "Usando un algoritmo voraz ordenando por valor.", "Probando todas las combinaciones posibles (fuerza bruta).", "Usando búsqueda binaria.", "No se puede resolver con programación dinámica."], respuestaCorrecta: 0, explicacion: "La matriz 2D permite construir la solución considerando dos opciones para cada ítem: incluirlo (si cabe) o excluirlo, tomando el máximo de ambos valores, evitando recalcular subproblemas." },
  { id: 99, curso: "Algoritmia", pregunta: "¿Qué diferencia hay entre DFS y BFS en términos de aplicación práctica?", opciones: ["DFS: ideal para explorar caminos, laberintos, detectar ciclos o componentes conexos (usa menos memoria). BFS: ideal para encontrar el camino más corto en grafos no ponderados o recorrer por niveles.", "Son intercambiables en todos los casos.", "DFS siempre encuentra el camino más corto.", "BFS usa menos memoria que DFS.", "DFS es iterativo y BFS es recursivo."], respuestaCorrecta: 0, explicacion: "DFS profundiza lo máximo posible antes de retroceder (pila), mientras que BFS explora todos los vecinos de un nivel antes de avanzar al siguiente (cola), lo que garantiza el camino más corto en grafos sin pesos." },
  { id: 100, curso: "Algoritmia", pregunta: "¿Cómo decidirías qué algoritmo usar entre búsqueda, ordenamiento, greedy, recursión o programación dinámica según el problema?", opciones: ["Búsqueda: datos ordenados (binaria). Ordenamiento: depende de tamaño/estabilidad. Greedy: optimización local funciona. DP: subproblemas superpuestos. Recursión: estructura natural de árbol/división.", "Elegir siempre el más complejo.", "Elegir siempre el más simple.", "Usar fuerza bruta para todo.", "No hay forma de decidir, es adivinanza."], respuestaCorrecta: 0, explicacion: "La elección del algoritmo se basa en las propiedades del problema: si los datos están ordenados, si hay subestructura óptima, si se necesita el camino más corto, o si el tamaño de entrada permite soluciones exponenciales." }
];